$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_83112255bb4233cad4276eab160483e8'] = 'Schaltet den Cleaner ein oder aus. Wenn deaktiviert, löschen weder die Cron-URL noch die Schaltfläche für die manuelle Ausführung alte Statistiken. Verwenden Sie diesen Schalter, wenn das Modul installiert bleiben, aber die Bereinigung vorübergehend gestoppt werden soll.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_896e1fd6ab19d8bbd2f58f989fbaac76'] = 'Aufbewahrungstage für Verbindungsstatistiken';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_b878a67f82524d412dae79ad597ff402'] = 'Ältere Zeilen werden aus connections, connections_source und connections_page entfernt.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_5ee406d769ac3887713d3308a0d01601'] = 'Geben Sie die Anzahl der Tage ein, für die rohe PrestaShop-Besucherstatistiken aufbewahrt werden sollen. Beispiel: 60 bedeutet, dass die letzten 60 Tage behalten und ältere Datensätze aus ps_connections, ps_connections_source und ps_connections_page gelöscht werden. Setzen Sie dies nicht auf 1, wenn Sie aktuelle Besucherstatistiken möglicherweise noch benötigen.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_1300769d8d72fc8218b40772f1c25efc'] = 'Batchgröße';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_631c4c75cb36e0fcee3da42ef67e730e'] = 'Maximale Anzahl von Verbindungen, die in einem Batch verarbeitet werden.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_acbc6e359c79ace4ef9b5398148c13e2'] = 'Geben Sie ein, wie viele Haupt-Verbindungsdatensätze in einem internen Batch verarbeitet werden dürfen. Kleinere Werte sind auf schwachem Hosting sicherer, erfordern aber mehr Cron-Läufe. Größere Werte bereinigen schneller, können Datenbanksperren aber länger halten. Empfohlener Startwert: 1000 bis 5000; erst nach Test der Laufzeit erhöhen.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2806977593fb4c23003cc11306b135d1'] = 'Maximale Batches pro Ausführung';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d31a094a19379b58b63b51ef0f9d9362'] = 'Begrenzt, wie viel Arbeit eine Cron-Ausführung erledigen kann.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_e221a5a91ea62a43adc5bb15614eb578'] = 'Geben Sie ein, wie viele Batches während einer Cron-Ausführung laufen dürfen. Die mögliche Gesamtzahl gelöschter Haupt-Verbindungsdatensätze pro Lauf entspricht ungefähr Batchgröße mal maximale Batches pro Lauf. Beispiel: 5000 und 10 bedeutet bis zu etwa 50000 Haupt-Verbindungsdatensätze in einem Cron-Lauf. Senken Sie den Wert, wenn der Shop während der Bereinigung langsamer wird.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a1a47524ffa9c839887703df1fbe70a3'] = 'ps_layered_filter_block leeren';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_924684322fe68e56ef9205e7f480f598'] = 'Leert den Cache-Block der facettierten/Layered-Suche mit TRUNCATE TABLE. Die Tabelle wird von MySQL/MariaDB leer neu erstellt.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Nur aktivieren, wenn ps_layered_filter_block zu stark wächst oder veralteten Cache der facettierten Suche enthält. Produkte, Kategorien oder der Layered-Preisindex werden nicht gelöscht. Nach der Bereinigung kann PrestaShop oder das Modul für facettierte Suche diesen Cache bei Bedarf neu aufbauen.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_bf45506cce2494894a9df6ff4bdf83ae'] = 'Traffic-Quellen-Statistiken vor dem Löschen aggregieren';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d7e1a0c7e7973ebcde37aa659525105d'] = 'Speichert tägliche zusammengefasste Traffic-Quellen-Statistiken vor dem Löschen roher Zeilen.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ae729759e10d7a626a8622321932a1f4'] = 'Wenn aktiviert, speichert das Modul vor dem Entfernen roher PrestaShop-Statistiken eine kleine tägliche Zusammenfassung. Es speichert Zähler wie Besuche, Seitenaufrufe, Quelldomain und UTM-Werte. IP-Adressen, vollständige Referrer-URLs oder User-Agent-Zeichenketten werden nicht gespeichert. Deaktivieren Sie dies, wenn Sie nur löschen möchten und keine historischen Quellenzusammenfassungen benötigen.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ce2b282d224153cccd645f28504ab4e2'] = 'Aufbewahrungstage für aggregierte Statistiken';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_c3b4d14f7bff29c221039e891918f2dd'] = 'Wie lange die kleine tägliche Zusammenfassungstabelle aufbewahrt werden soll.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a97a6a6ab09f48206a543fdc7321bb60'] = 'Geben Sie ein, wie viele Tage aggregierte Traffic-Quellen-Zusammenfassungen in der Modultabelle verbleiben sollen. Beispiel: 730 speichert etwa zwei Jahre tägliche Quellenzusammenfassungen. Diese Einstellung betrifft nur die Modultabelle ps_jooim_dbcleaner_traffic_daily, nicht die ursprünglichen PrestaShop-Statistiktabellen.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_4d4c70d739ad72835a8b62a81e07c611'] = 'Timeout für veraltete Sperre in Sekunden';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Schutz davor, dass zwei Bereinigungsprozesse gleichzeitig laufen.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2c1824ea38ec688698a26f01a46e6b16'] = 'Geben Sie die Anzahl der Sekunden ein, nach denen eine nicht abgeschlossene Bereinigungssperre als verlassen gilt. Dies schützt die Datenbank davor, dass zwei Cron-Ausführungen gleichzeitig laufen. Empfohlener Wert: 7200. Nur senken, wenn Ihr Cron garantiert schnell beendet wird.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_c9cc8cce247e49bae79f15173ce97354'] = 'Speichern';
