$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_bf45506cce2494894a9df6ff4bdf83ae'] = 'Traffic-Quellen-Statistiken vor dem Löschen aggregieren';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_d7e1a0c7e7973ebcde37aa659525105d'] = 'Speichert tägliche zusammengefasste Traffic-Quellen-Statistiken vor dem Löschen roher Zeilen.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ae729759e10d7a626a8622321932a1f4'] = 'Wenn aktiviert, speichert das Modul vor dem Entfernen roher PrestaShop-Statistiken eine kleine tägliche Zusammenfassung. Es speichert Zähler wie Besuche, Seitenaufrufe, Quelldomain und UTM-Werte. IP-Adressen, vollständige Referrer-URLs oder User-Agent-Zeichenketten werden nicht gespeichert. Deaktivieren Sie dies, wenn Sie nur löschen möchten und keine historischen Quellenzusammenfassungen benötigen.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ce2b282d224153cccd645f28504ab4e2'] = 'Aufbewahrungstage für aggregierte Statistiken';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_c3b4d14f7bff29c221039e891918f2dd'] = 'Wie lange die kleine tägliche Zusammenfassungstabelle aufbewahrt werden soll.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_a97a6a6ab09f48206a543fdc7321bb60'] = 'Geben Sie ein, wie viele Tage aggregierte Traffic-Quellen-Zusammenfassungen in der Modultabelle verbleiben sollen. Beispiel: 730 speichert etwa zwei Jahre tägliche Quellenzusammenfassungen. Diese Einstellung betrifft nur die Modultabelle ps_jooim_dbcleaner_traffic_daily, nicht die ursprünglichen PrestaShop-Statistiktabellen.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_4d4c70d739ad72835a8b62a81e07c611'] = 'Timeout für veraltete Sperre in Sekunden';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Schutz davor, dass zwei Bereinigungsprozesse gleichzeitig laufen.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_2c1824ea38ec688698a26f01a46e6b16'] = 'Geben Sie die Anzahl der Sekunden ein, nach denen eine nicht abgeschlossene Bereinigungssperre als verlassen gilt. Dies schützt die Datenbank davor, dass zwei Cron-Ausführungen gleichzeitig laufen. Empfohlener Wert: 7200. Nur senken, wenn Ihr Cron garantiert schnell beendet wird.';
